/**
 * Unit Tests for AI Controller
 * Tests AI controller functions with mocked dependencies
 */

import { Request, Response } from 'express';
import {
  generateNatal,
  generateTransit,
  generateCompatibility,
  generateLunarReturn,
  generateSolarReturn,
  checkStatus,
  getUsageStats,
  clearCache,
} from '../../modules/ai/controllers/ai.controller';

// Mock the AI services
jest.mock('../../modules/ai/services/aiInterpretation.service');
jest.mock('../../modules/ai/services/openai.service');
jest.mock('../../utils/logger');

import aiInterpretationService from '../../modules/ai/services/aiInterpretation.service';
import openaiService from '../../modules/ai/services/openai.service';

describe('AI Controller', () => {
  let mockRequest: Partial<Request>;
  let mockResponse: Partial<Response>;
  let responseObject: any;

  beforeEach(() => {
    // Reset mocks
    jest.clearAllMocks();

    // Setup mock response
    responseObject = {
      json: jest.fn().mockReturnThis(),
      status: jest.fn().mockReturnThis(),
    };

    mockResponse = responseObject as Response;

    // Setup mock request with user
    mockRequest = {
      user: { userId: 1, email: 'test@example.com' },
      body: {},
    };
  });

  describe('generateNatal', () => {
    it('should generate AI natal interpretation successfully', async () => {
      const chartData = {
        planets: [
          { planet: 'sun', sign: 'aries', degree: 15, house: 1 },
        ],
      };

      mockRequest.body = chartData;

      const mockInterpretation = {
        ai: true,
        source: 'ai-enhanced',
        overview: { text: 'Test interpretation' },
        planetsInSigns: [],
        houses: [],
        aspects: [],
        patterns: [],
      };

      (aiInterpretationService.generateNatal as jest.Mock).mockResolvedValue(mockInterpretation);

      await generateNatal(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: mockInterpretation,
      });

      expect(aiInterpretationService.generateNatal).toHaveBeenCalledWith(chartData);
    });

    it('should return 400 when planets are missing', async () => {
      mockRequest.body = {};

      await expect(
        generateNatal(mockRequest as Request, mockResponse as Response)
      ).rejects.toThrow();

      expect(aiInterpretationService.generateNatal).not.toHaveBeenCalled();
    });
  });

  describe('generateTransit', () => {
    it('should generate AI transit forecast successfully', async () => {
      const transitData = {
        currentTransits: [
          {
            planet: 'Jupiter',
            type: 'conjunction',
            natalPlanet: 'Sun',
            orb: 3,
            startDate: '2024-01-15',
            endDate: '2024-02-20',
          },
        ],
      };

      mockRequest.body = transitData;

      const mockForecast = {
        ai: true,
        forecast: 'Test forecast',
      };

      (aiInterpretationService.generateTransit as jest.Mock).mockResolvedValue(mockForecast);

      await generateTransit(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: mockForecast,
      });

      expect(aiInterpretationService.generateTransit).toHaveBeenCalledWith(transitData);
    });

    it('should return 400 when transits are missing', async () => {
      mockRequest.body = {};

      await expect(
        generateTransit(mockRequest as Request, mockResponse as Response)
      ).rejects.toThrow();

      expect(aiInterpretationService.generateTransit).not.toHaveBeenCalled();
    });
  });

  describe('generateCompatibility', () => {
    it('should generate AI compatibility analysis successfully', async () => {
      const synastryData = {
        chartA: {
          planets: [{ planet: 'sun', sign: 'aries', degree: 15, house: 1 }],
        },
        chartB: {
          planets: [{ planet: 'sun', sign: 'libra', degree: 10, house: 7 }],
        },
      };

      mockRequest.body = synastryData;

      const mockAnalysis = {
        ai: true,
        compatibility: 85,
        analysis: 'Strong compatibility',
      };

      (aiInterpretationService.generateCompatibility as jest.Mock).mockResolvedValue(mockAnalysis);

      await generateCompatibility(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: mockAnalysis,
      });

      expect(aiInterpretationService.generateCompatibility).toHaveBeenCalledWith(synastryData);
    });

    it('should return 400 when chartA is missing', async () => {
      mockRequest.body = {
        chartB: { planets: [{ planet: 'sun', sign: 'aries', degree: 15, house: 1 }] },
      };

      await expect(
        generateCompatibility(mockRequest as Request, mockResponse as Response)
      ).rejects.toThrow();
    });

    it('should return 400 when chartB is missing', async () => {
      mockRequest.body = {
        chartA: { planets: [{ planet: 'sun', sign: 'aries', degree: 15, house: 1 }] },
      };

      await expect(
        generateCompatibility(mockRequest as Request, mockResponse as Response)
      ).rejects.toThrow();
    });
  });

  describe('generateLunarReturn', () => {
    it('should generate AI lunar return interpretation successfully', async () => {
      const chartData = {
        planets: [
          { planet: 'moon', sign: 'cancer', degree: 15, house: 4 },
        ],
      };

      mockRequest.body = chartData;

      const mockInterpretation = {
        ai: true,
        interpretation: 'Monthly forecast',
      };

      (aiInterpretationService.generateLunarReturn as jest.Mock).mockResolvedValue(mockInterpretation);

      await generateLunarReturn(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: mockInterpretation,
      });

      expect(aiInterpretationService.generateLunarReturn).toHaveBeenCalledWith(chartData);
    });

    it('should return 400 when planets are missing', async () => {
      mockRequest.body = {};

      await expect(
        generateLunarReturn(mockRequest as Request, mockResponse as Response)
      ).rejects.toThrow();
    });
  });

  describe('generateSolarReturn', () => {
    it('should generate AI solar return interpretation successfully', async () => {
      const chartData = {
        planets: [
          { planet: 'sun', sign: 'aries', degree: 15, house: 1 },
        ],
      };

      mockRequest.body = chartData;

      const mockInterpretation = {
        ai: true,
        interpretation: 'Yearly forecast',
      };

      (aiInterpretationService.generateSolarReturn as jest.Mock).mockResolvedValue(mockInterpretation);

      await generateSolarReturn(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: mockInterpretation,
      });

      expect(aiInterpretationService.generateSolarReturn).toHaveBeenCalledWith(chartData);
    });

    it('should return 400 when planets are missing', async () => {
      mockRequest.body = {};

      await expect(
        generateSolarReturn(mockRequest as Request, mockResponse as Response)
      ).rejects.toThrow();
    });
  });

  describe('checkStatus', () => {
    it('should return AI service status', async () => {
      const mockStatus = {
        configured: true,
        model: 'gpt-4-turbo',
        maxTokens: 2000,
        temperature: 0.7,
      };

      (openaiService.isConfigured as jest.Mock).mockReturnValue(true);
      (openaiService.getConfigStatus as jest.Mock).mockReturnValue(mockStatus);

      await checkStatus(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: {
          available: true,
          service: 'openai',
          ...mockStatus,
        },
      });

      expect(openaiService.isConfigured).toHaveBeenCalled();
      expect(openaiService.getConfigStatus).toHaveBeenCalled();
    });

    it('should return unavailable when not configured', async () => {
      (openaiService.isConfigured as jest.Mock).mockReturnValue(false);
      (openaiService.getConfigStatus as jest.Mock).mockReturnValue({
        configured: false,
        model: 'gpt-4-turbo',
        maxTokens: 2000,
        temperature: 0.7,
      });

      await checkStatus(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: {
          available: false,
          service: null,
          configured: false,
          model: 'gpt-4-turbo',
          maxTokens: 2000,
          temperature: 0.7,
        },
      });
    });
  });

  describe('getUsageStats', () => {
    it('should return AI usage statistics', async () => {
      const mockStats = {
        available: true,
        usage: {
          totalRequests: 100,
          totalTokens: 50000,
          totalCost: 0.5,
        },
      };

      (openaiService.getUsageStats as jest.Mock).mockResolvedValue(mockStats);

      await getUsageStats(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: mockStats,
      });

      expect(openaiService.getUsageStats).toHaveBeenCalled();
    });
  });

  describe('clearCache', () => {
    it('should clear AI interpretation cache', async () => {
      (aiInterpretationService.clearCache as jest.Mock).mockResolvedValue(undefined);

      await clearCache(mockRequest as Request, mockResponse as Response);

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        message: 'Cache cleared successfully',
      });

      expect(aiInterpretationService.clearCache).toHaveBeenCalled();
    });
  });
});

/**
 * AI Interpretation Service Tests
 * Tests hybrid AI/rule-based interpretation service
 */

process.env.NODE_ENV = 'test';

const mockLogger = {
  error: jest.fn(),
  info: jest.fn(),
  warn: jest.fn(),
  debug: jest.fn(),
};

jest.mock('../../utils/logger', () => ({
  default: mockLogger,
  __esModule: true,
}));

// Mock the analysis module
const mockGenerateCompletePersonalityAnalysis = jest.fn();
jest.mock('../../modules/analysis/services/interpretation.service', () => ({
  generateCompletePersonalityAnalysis: mockGenerateCompletePersonalityAnalysis,
}));

import { describe, it, expect, beforeEach } from '@jest/globals';

describe('AI Interpretation Service - Basic Functionality', () => {
  let aiInterpretationService: any;
  let openaiService: any;
  let aiCacheService: any;

  beforeAll(() => {
    // Import after mocks are set up
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    aiInterpretationService = require('../../modules/ai/services/aiInterpretation.service').default;
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    openaiService = require('../../modules/ai/services/openai.service').default;
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    aiCacheService = require('../../modules/ai/services/aiCache.service').default;
  });

  beforeEach(() => {
    jest.clearAllMocks();
    // Reset all mocks
    mockGenerateCompletePersonalityAnalysis.mockReset();
  });

  describe('generateNatal', () => {
    it('should fallback to rule-based when AI is not configured', async () => {
      // Mock isConfigured to return false
      openaiService.isConfigured = jest.fn().mockReturnValue(false);

      const chartData = {
        planets: [
          { planet: 'sun', sign: 'aries', degree: 15, house: 1 },
        ],
      };

      const mockRuleBased = {
        overview: { sunSign: { sign: 'aries' } },
        planetsInSigns: [],
        houses: [],
        aspects: [],
        patterns: [],
      };

      mockGenerateCompletePersonalityAnalysis.mockReturnValue(mockRuleBased);

      const result = await aiInterpretationService.generateNatal(chartData);

      expect(result).toBeDefined();
      expect(result).toHaveProperty('ai', false);
      expect(result).toHaveProperty('source', 'rule-based');
      expect(result).toHaveProperty('overview');
    });

    it('should return valid interpretation structure', async () => {
      openaiService.isConfigured = jest.fn().mockReturnValue(false);

      const chartData = {
        planets: [{ planet: 'sun', sign: 'aries', degree: 15, house: 1 }],
      };

      mockGenerateCompletePersonalityAnalysis.mockReturnValue({
        overview: {},
        planetsInSigns: [],
        houses: [],
        aspects: [],
        patterns: [],
      });

      const result = await aiInterpretationService.generateNatal(chartData);

      expect(result).toBeDefined();
      expect(result).toHaveProperty('ai');
      expect(result).toHaveProperty('source');
    });
  });

  describe('generateTransit', () => {
    it('should fallback to rule-based when AI unavailable for transits', async () => {
      openaiService.isConfigured = jest.fn().mockReturnValue(false);

      const transitData = {
        currentTransits: [
          { planet: 'jupiter', type: 'trine', natalPlanet: 'sun' },
        ],
      };

      const result = await aiInterpretationService.generateTransit(transitData);

      expect(result).toBeDefined();
      expect(result).toHaveProperty('ai', false);
      expect(result).toHaveProperty('source', 'rule-based');
      expect(result).toHaveProperty('forecast');
    });
  });

  describe('generateCompatibility', () => {
    it('should fallback when AI unavailable for compatibility', async () => {
      openaiService.isConfigured = jest.fn().mockReturnValue(false);

      const synastryData = {
        chartA: { planets: [] },
        chartB: { planets: [] },
      };

      const result = await aiInterpretationService.generateCompatibility(synastryData);

      expect(result).toBeDefined();
      expect(result).toHaveProperty('ai', false);
      expect(result).toHaveProperty('compatibility', 50);
      expect(result).toHaveProperty('analysis');
    });
  });

  describe('batchGenerateNatal', () => {
    it('should handle batch processing', async () => {
      openaiService.isConfigured = jest.fn().mockReturnValue(false);

      const charts = [
        { planets: [{ planet: 'sun', sign: 'aries', degree: 15, house: 1 }] },
        { planets: [{ planet: 'sun', sign: 'taurus', degree: 20, house: 2 }] },
      ];

      mockGenerateCompletePersonalityAnalysis.mockReturnValue({
        overview: {},
        planetsInSigns: [],
        houses: [],
        aspects: [],
        patterns: [],
      });

      const results = await aiInterpretationService.batchGenerateNatal(charts);

      expect(results).toHaveLength(2);
      expect(results[0]).toHaveProperty('chartIndex', 0);
      expect(results[0]).toHaveProperty('success');
      expect(results[1]).toHaveProperty('chartIndex', 1);
      expect(results[1]).toHaveProperty('success');
    });
  });

  describe('service status', () => {
    it('should return service status', () => {
      const status = aiInterpretationService.getStatus();

      expect(status).toBeDefined();
      expect(status).toHaveProperty('aiConfigured');
      expect(status).toHaveProperty('cacheEnabled');
      expect(status).toHaveProperty('fallbackAvailable');
    });

    it('should check if AI is configured', () => {
      openaiService.isConfigured = jest.fn().mockReturnValue(true);

      const isConfigured = aiInterpretationService.isAIConfigured();

      expect(typeof isConfigured).toBe('boolean');
    });
  });

  describe('cache management', () => {
    it('should expose clearCache method', async () => {
      aiCacheService.clear = jest.fn().mockResolvedValue(undefined);

      await aiInterpretationService.clearCache();

      expect(aiCacheService.clear).toHaveBeenCalled();
    });
  });
});

/**
 * Integration Test Utilities for AI Tests
 * Helper functions for AI integration tests
 */

import bcrypt from 'bcryptjs';

/**
 * Clean database tables
 */
export async function cleanDatabase(database: any) {
  const tables = [
    'refresh_tokens',
    'ai_cache',
    'charts',
    'users',
  ];

  for (const table of tables) {
    await database(table).del();
  }
}

/**
 * Create test user in database
 */
export async function createTestUser(database: any) {
  const hashedPassword = await bcrypt.hash('Password123!', 10);

  const [user] = await database('users')
    .insert({
      email: 'test@example.com',
      password: hashedPassword,
      name: 'Test User',
      subscription_tier: 'free',
    })
    .returning('*');

  return user;
}

/**
 * Create authenticated test user with token
 */
export async function createAuthenticatedUser(database: any, request: any) {
  await createTestUser(database);

  const loginResponse = await request
    .post('/api/v1/auth/login')
    .send({
      email: 'test@example.com',
      password: 'Password123!',
    });

  return {
    user: loginResponse.body.data.user,
    token: loginResponse.body.data.token,
  };
}

/**
 * OpenAI Service Tests
 * Comprehensive test suite for AI-powered astrological interpretations
 */

/* eslint-disable @typescript-eslint/no-unused-vars */

// Set test environment before importing anything
process.env.NODE_ENV = 'test';
process.env.OPENAI_API_KEY = 'test-api-key'; // Set a test API key

// Mock logger before any imports
const mockLogger = {
  error: jest.fn(),
  info: jest.fn(),
  warn: jest.fn(),
  debug: jest.fn(),
};

jest.mock('../../utils/logger', () => ({
  default: mockLogger,
  __esModule: true,
}));

// Mock aiUsageService
const mockAiUsageService = {
  record: jest.fn().mockResolvedValue(undefined),
};

jest.mock('../../modules/ai/services/aiUsage.service', () => ({
  __esModule: true,
  default: mockAiUsageService,
}));

// Mock OpenAI module BEFORE importing service
const mockCreate = jest.fn();

const mockChat = {
  completions: {
    create: mockCreate,
  },
};

const mockOpenAIInstance = {
  chat: mockChat,
};

const MockOpenAI = jest.fn().mockImplementation(() => mockOpenAIInstance);

jest.mock('openai', () => ({
  __esModule: true,
  default: MockOpenAI,
}));

import { describe, it, expect, beforeEach, afterEach } from '@jest/globals';
import openaiService from '../../modules/ai/services/openai.service';

describe('OpenAI Service', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    openaiService.clearCache();
    // Default mock behavior
    mockCreate.mockResolvedValue({
      choices: [{ message: { content: 'test response' } }],
      usage: {
        prompt_tokens: 100,
        completion_tokens: 50,
      },
    });
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  describe('generateNatalInterpretation', () => {
    const validChartData = {
      planets: [
        { planet: 'sun', sign: 'aries', degree: 15, house: 1 },
        { planet: 'moon', sign: 'taurus', degree: 10, house: 2 },
      ],
      houses: [{ house: 1, sign: 'aries', degree: 0 }],
      aspects: [{ planet1: 'sun', planet2: 'moon', type: 'conjunction', orb: 5 }],
      birthDate: '1990-04-15',
      birthTime: '10:30',
      birthPlace: 'New York, NY',
    };

    it('should generate natal chart interpretation successfully', async () => {
      const mockResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                sunInAries: 'You are a natural leader...',
                moonInTaurus: 'You seek emotional stability...',
              }),
            },
          },
        ],
        usage: {
          prompt_tokens: 100,
          completion_tokens: 50,
        },
      };

      mockCreate.mockResolvedValueOnce(mockResponse);

      const result = await openaiService.generateNatalInterpretation(validChartData);

      expect(result.success).toBe(true);
      expect(result.interpretation).toBeDefined();
      expect(mockCreate).toHaveBeenCalledTimes(1);
    });

    it('should handle markdown text responses', async () => {
      const mockResponse = {
        choices: [
          {
            message: {
              content: '# Natal Chart Interpretation\n\nYour Sun in Aries...',
            },
          },
        ],
        usage: {
          prompt_tokens: 100,
          completion_tokens: 50,
        },
      };

      mockCreate.mockResolvedValueOnce(mockResponse);

      const result = await openaiService.generateNatalInterpretation(validChartData);

      expect(result.success).toBe(true);
      expect(result.interpretation.text).toBeDefined();
      expect(result.interpretation.generated).toBe(true);
    });

    it('should use cached interpretations on second call', async () => {
      const mockResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({ sunInAries: 'Test interpretation' }),
            },
          },
        ],
        usage: {
          prompt_tokens: 100,
          completion_tokens: 50,
        },
      };

      mockCreate.mockResolvedValueOnce(mockResponse);

      const result1 = await openaiService.generateNatalInterpretation(validChartData);
      const result2 = await openaiService.generateNatalInterpretation(validChartData);

      expect(result1.interpretation).toEqual(result2.interpretation);
      expect(result1.cached).toBe(false);
      expect(result2.cached).toBe(true);
      expect(mockCreate).toHaveBeenCalledTimes(1);
    });

    it('should validate input data', async () => {
      const invalidData = {
        planets: [],
      };

      const result = await openaiService.generateNatalInterpretation(invalidData as any);

      expect(result.success).toBe(false);
      expect(result.error).toContain('at least one planet');
    });

    it('should handle API errors gracefully', async () => {
      mockCreate.mockRejectedValueOnce(new Error('API Error'));

      const result = await openaiService.generateNatalInterpretation(validChartData);

      expect(result.success).toBe(false);
      expect(result.error).toBeDefined();
    });
  });

  describe('generateTransitForecast', () => {
    const validTransitData = {
      currentTransits: [
        {
          planet: 'Jupiter',
          type: 'conjunction',
          natalPlanet: 'Sun',
          orb: 3,
          startDate: '2024-01-15',
          endDate: '2024-02-20',
          strength: 'strong' as const,
        },
      ],
      forecastStartDate: '2024-01-01',
      forecastEndDate: '2024-03-31',
    };

    it('should generate transit forecast successfully', async () => {
      const mockResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                overallTheme: 'A period of expansion...',
                opportunities: ['Growth opportunities ahead...'],
              }),
            },
          },
        ],
        usage: {
          prompt_tokens: 100,
          completion_tokens: 50,
        },
      };

      mockCreate.mockResolvedValueOnce(mockResponse);

      const result = await openaiService.generateTransitForecast(validTransitData);

      expect(result.success).toBe(true);
      expect(result.interpretation).toBeDefined();
    });

    it('should validate transit input data', async () => {
      const invalidData = {
        currentTransits: [],
      };

      const result = await openaiService.generateTransitForecast(invalidData as any);

      expect(result.success).toBe(false);
      expect(result.error).toContain('at least one transit');
    });
  });

  describe('generateCompatibilityAnalysis', () => {
    const validSynastryData = {
      chartA: {
        planets: [{ planet: 'sun', sign: 'aries', degree: 15, house: 1 }],
      },
      chartB: {
        planets: [{ planet: 'sun', sign: 'libra', degree: 20, house: 7 }],
      },
    };

    it('should generate compatibility analysis successfully', async () => {
      const mockResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                strengths: ['Your Suns create balance...'],
                challenges: ['Different emotional needs...'],
              }),
            },
          },
        ],
        usage: {
          prompt_tokens: 100,
          completion_tokens: 50,
        },
      };

      mockCreate.mockResolvedValueOnce(mockResponse);

      const result = await openaiService.generateCompatibilityAnalysis(validSynastryData);

      expect(result.success).toBe(true);
      expect(result.interpretation).toBeDefined();
    });

    it('should validate synastry input data', async () => {
      const invalidData = {
        chartA: null,
        chartB: null,
      };

      const result = await openaiService.generateCompatibilityAnalysis(invalidData as any);

      expect(result.success).toBe(false);
      expect(result.error).toContain('must include both charts');
    });
  });

  describe('generateLunarReturnInterpretation', () => {
    it('should generate lunar return interpretation successfully', async () => {
      const chartData = {
        planets: [{ planet: 'sun', sign: 'cancer', degree: 10, house: 4 }],
      };

      const mockResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                emotionalTheme: 'A month of sensitivity...',
              }),
            },
          },
        ],
        usage: {
          prompt_tokens: 100,
          completion_tokens: 50,
        },
      };

      mockCreate.mockResolvedValueOnce(mockResponse);

      const result = await openaiService.generateLunarReturnInterpretation(chartData);

      expect(result.success).toBe(true);
      expect(result.interpretation).toBeDefined();
    });
  });

  describe('generateSolarReturnInterpretation', () => {
    it('should generate solar return interpretation successfully', async () => {
      const chartData = {
        planets: [{ planet: 'sun', sign: 'leo', degree: 5, house: 5 }],
      };

      const mockResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                yearTheme: 'A year of creativity...',
              }),
            },
          },
        ],
        usage: {
          prompt_tokens: 100,
          completion_tokens: 50,
        },
      };

      mockCreate.mockResolvedValueOnce(mockResponse);

      const result = await openaiService.generateSolarReturnInterpretation(chartData);

      expect(result.success).toBe(true);
      expect(result.interpretation).toBeDefined();
    });
  });

  describe('Configuration Status', () => {
    it('should report configuration status', () => {
      const status = openaiService.getConfigStatus();

      expect(status).toHaveProperty('configured');
