  const transactionFn = jest.fn().mockImplementation(async (callback: (trx: any) => Promise<any>) => {
    callCount = 0;
    return callback(mockTrx);
  });

  return {
    __esModule: true,
    default: {
      transaction: transactionFn,
    },
  };
});

