      const planets = ['sun', 'moon', 'mercury', 'venus', 'mars', 'jupiter', 'saturn', 'uranus', 'neptune', 'pluto'];
      const test = new PerformanceTest('All 10 Planets', 50, 5000);

      const result = await test.run(() => {
        planets.forEach(planet => {
