/**
 * Solar Return Chart planet data
 */
interface SolarReturnPlanet {
  planet: string;
  house: number;
}

/**
 * Solar return aspect data
 */
interface SolarReturnAspect {
  type: string;
}

/**
 * Solar return chart data
 */
interface SolarReturnChartData {
  planets: SolarReturnPlanet[];
  houses: SolarReturnHouseCusp[];
  aspects: SolarReturnAspect[];
  ascendant: SolarReturnAscendant;
  mc: SolarReturnMc;
  moonPhase: { phase: string };
}

export function generateSolarReturnInterpretation(
  chartData: SolarReturnChartData,
  _year: number,
): SolarReturnInterpretation {
  // Determine sun's house placement
  const sunPlanet = chartData.planets.find((p) => p.planet === 'sun');
  const sunHouse = sunPlanet?.house ?? 1;

  // Get sun in house interpretation
  const sunInHouseData = SUN_IN_HOUSES[sunHouse];

  // Generate themes
  const themes: string[] = [
    ...sunInHouseData.themes,
    ...generatePlanetaryThemes(chartData.planets),
  ];

  // Generate challenges
  const challenges = generateChallenges(chartData);

  // Generate opportunities
  const opportunities = generateOpportunities(chartData);

  // Generate advice
  const advice = generateAdvice(sunHouse, chartData);

  return {
    themes,
    sunHouse: {
      house: sunHouse,
      interpretation: sunInHouseData.interpretation,
      focus: sunInHouseData.focus,
    },
    moonPhase: {
      phase: chartData.moonPhase?.phase || 'new',
      ...MOON_PHASES[chartData.moonPhase?.phase || 'new'],
    },
    luckyDays: [], // Will be calculated separately
    challenges,
    opportunities,
    advice,
    keywords: generateKeywords(sunHouse, chartData),
  };
}

/**
 * Generate planetary themes
 */
function generatePlanetaryThemes(planets: SolarReturnPlanet[]): string[] {
  const themes: string[] = [];

  for (const planet of planets) {
    const planetThemes = PLANET_IN_HOUSE[planet.planet]?.[planet.house];
    if (planetThemes) {
      themes.push(planetThemes);
    }
  }

  return themes;
}

/**
 * Generate challenges
 */
function generateChallenges(chartData: any): Array<{
  area: string;
  description: string;
  advice: string;
}> {
  const challenges: Array<{
    area: string;
    description: string;
    advice: string;
  }> = [];

  // Saturn challenges
  const saturn = chartData.planets?.find((p: SolarReturnPlanet) => p.planet === 'saturn');
  if (saturn) {
    const saturnChallenges: Record<number, { area: string; description: string; advice: string }> = {
      1: {
        area: "Self-Expression",
