        advice: "Embrace the hard work. What you build now will form the foundation of future success."
      },
    };

    const challenge = saturnChallenges[saturn.house];
    if (challenge) {
      challenges.push(challenge);
    }
  }

  return challenges;
}

/**
 * Generate opportunities
 */
function generateOpportunities(chartData: { planets?: SolarReturnPlanet[] }): Array<{
  area: string;
  description: string;
  timing: string;
}> {
  const opportunities: Array<{
    area: string;
