export async function compareCharts(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
  try {
    const userId = req.user.id;

    if (!userId) {
      res.status(401).json({
        success: false,
        error: 'Unauthorized',
      });
    }

    const { chart1Id, chart2Id } = req.body;

    if (!chart1Id || !chart2Id) {
      res.status(400).json({
        success: false,
        error: 'chart1Id and chart2Id are required',
      });
    }

    if (chart1Id === chart2Id) {
      res.status(400).json({
        success: false,
        error: 'Cannot compare a chart with itself',
      });
    }

    // Fetch both charts from database
    const [chart1Data, chart2Data] = await Promise.all([
      knex('charts').where({ id: chart1Id }).first(),
      knex('charts').where({ id: chart2Id }).first(),
    ]);

    if (!chart1Data || !chart2Data) {
      res.status(404).json({
        success: false,
        error: 'One or both charts not found',
      });
    }

    // Build chart objects
    const chart1: Chart = {
      id: chart1Data.id,
      userId: chart1Data.userId,
      planets: {
        sun: chart1Data.sunSign ? {
          name: 'sun',
          degree: chart1Data.sunDegree || 0,
          minute: chart1Data.sunMinute || 0,
          second: chart1Data.sunSecond || 0,
