          minute: chart2Data.plutoMinute || 0,
          second: chart2Data.plutoSecond || 0,
          sign: chart2Data.plutoSign,
        } : undefined,
      },
    };

    // Calculate synastry
    const synastryChart = calculateSynastryChart(chart1, chart2);

    // Check if already exists
    const existingSynastry = await knex('synastry_charts')
      .where({
        chart1_id: chart1Id,
        chart2_id: chart2Id,
        user_id: userId,
      })
      .first();

    let synastryId = existingSynastry?.id;

    // Save to database if new
    if (!synastryId) {
      const [inserted] = await knex('synastry_charts')
        .insert({
          chart1_id: chart1Id,
          chart2_id: chart2Id,
          user_id: userId,
          synastry_aspects: JSON.stringify(synastryChart.synastryAspects),
          compatibility_score: synastryChart.overallCompatibility,
          relationship_theme: synastryChart.relationshipTheme,
          strengths: synastryChart.strengths,
          challenges: synastryChart.challenges,
          advice: synastryChart.advice,
          created_at: new Date().toISOString(),
          updated_at: new Date().toISOString(),
        })
        .returning('id');

      synastryId = inserted[0].id;

      // Insert aspects
      for (const aspect of synastryChart.synastryAspects) {
        await knex('synastry_aspects').insert({
          synastry_chart_id: synastryId,
          planet1: aspect.planet1,
          planet2: aspect.planet2,
          aspect: aspect.aspect,
          orb: aspect.orb,
          applying: aspect.applying,
          interpretation: aspect.interpretation,
          weight: aspect.weight,
          soulmate_indicator: aspect.soulmateIndicator,
          created_at: new Date().toISOString(),
        });
      }
    }

    res.json({
      success: true,
      data: {
        ...synastryChart,
        id: synastryId,
      },
    });
  } catch (error) {
    next(error);
  }
}

/**
 * Calculate compatibility score
 * POST /synastry/compatibility
 */
export async function getCompatibility(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
  try {
    const userId = req.user.id;

    if (!userId) {
      res.status(401).json({
        success: false,
        error: 'Unauthorized',
      });
    }

    const { chart1Id, chart2Id, includeComposite = false } = req.body;

    if (!chart1Id || !chart2Id) {
      res.status(400).json({
        success: false,
        error: 'chart1Id and chart2Id are required',
      });
    }

    // Fetch both charts
    const [chart1Data, chart2Data] = await Promise.all([
      knex('charts').where({ id: chart1Id }).first() as Promise<Record<string, unknown> | undefined>,
      knex('charts').where({ id: chart2Id }).first() as Promise<Record<string, unknown> | undefined>,
    ]);

    if (!chart1Data || !chart2Data) {
      res.status(404).json({
        success: false,
        error: 'One or both charts not found',
      });
    }

    // Build simplified chart objects for calculation
    const chart1: Chart = {
      id: chart1Data.id as string,
      userId: chart1Data.userId as string,
      planets: {},
    };

    const chart2: Chart = {
      id: chart2Data.id as string,
      userId: chart2Data.userId as string,
      planets: {},
    };

    // Populate planets for both charts
    const planets = ['sun', 'moon', 'mercury', 'venus', 'mars', 'jupiter', 'saturn', 'uranus', 'neptune', 'pluto'] as const;
    planets.forEach((planet) => {
      const signField = `${planet}Sign` as keyof typeof chart1Data;
      const degreeField = `${planet}Degree` as keyof typeof chart1Data;
      const minuteField = `${planet}Minute` as keyof typeof chart1Data;
      const secondField = `${planet}Second` as keyof typeof chart1Data;

      if (chart1Data[signField]) {
        chart1.planets[planet] = {
          name: planet,
          degree: (chart1Data[degreeField] as number) || 0,
          minute: (chart1Data[minuteField] as number) || 0,
          second: (chart1Data[secondField] as number) || 0,
          sign: chart1Data[signField] as string,
        };
      }

      if (chart2Data[signField]) {
        chart2.planets[planet] = {
          name: planet,
          degree: (chart2Data[degreeField] as number) || 0,
          minute: (chart2Data[minuteField] as number) || 0,
          second: (chart2Data[secondField] as number) || 0,
          sign: chart2Data[signField] as string,
        };
      }
    });

    // Calculate scores
    const scores = calculateCategoryScores(chart1, chart2);
    const elementalBalance = calculateElementalBalance(chart1, chart2);

    const result: Record<string, unknown> = {
      chart1Id,
      chart2Id,
      scores,
      elementalBalance,
    };

    // Add composite chart if requested
    if (includeComposite) {
      result.compositeChart = calculateCompositeChart(chart1, chart2);
    }

    res.json({
      success: true,
      data: result,
    });
  } catch (error) {
    next(error);
  }
}

/**
 * Get all synastry comparisons for user
 * GET /synastry/reports
 */
export async function getSynastryReports(req: Request, res: Response, next: NextFunction): Promise<void> {
  try {
    const userId = (req as any).user?.id;

    if (!userId) {
      res.status(401).json({
        success: false,
        error: 'Unauthorized',
      });
    }

    const page = parseInt(req.query.page as string) || 1;
    const limit = parseInt(req.query.limit as string) || 10;
    const offset = (page - 1) * limit;

    const reports = await knex('synastry_charts')
      .where({ user_id: userId })
      .orderBy('created_at', 'desc')
      .limit(limit)
      .offset(offset);

    const total = await knex('synastry_charts')
      .where({ user_id: userId })
      .count('* as count')
      .first();

    res.json({
      success: true,
      data: {
        reports: reports.map((r: any) => ({
          id: r.id,
          chart1Id: r.chart1_id,
          chart2Id: r.chart2_id,
          synastryAspects: JSON.parse(r.synastry_aspects || '[]'),
          overallCompatibility: r.compatibility_score,
          relationshipTheme: r.relationship_theme,
          strengths: r.strengths || [],
          challenges: r.challenges || [],
          advice: r.advice,
          isFavorite: r.is_favorite,
          notes: r.notes,
          createdAt: r.created_at,
        })),
        pagination: {
          page,
          limit,
          total: (total as any).count,
          totalPages: Math.ceil((total as any).count / limit),
        },
      },
    });
  } catch (error) {
    next(error);
  }
}

